INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028542e3c98b09417661f5', '花园酒店博物馆入场券（逢周一闭馆）:每次必住的酒店', '["https://dimg04.c-ctrip.com/images/0233g12000bjqmnyx7F43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000bjqc7cdD8C6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-01', '花园大床房', '大床房', '商务出差', 25, 0, 133, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b09417661f6', '很方便的一家酒店，个人很喜欢', '["https://dimg04.c-ctrip.com/images/0235c12000bqqsrco2B9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000bqqpg6q9E06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000bqqzap49A3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000bqqt7pn9134_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-07-25', '花园双床房', '双床房', '家庭亲子', 14, 0, 21, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b09417661f7', '花园酒店在广州也算是老牌酒店了，第一次来住，酒店很大，大堂走进去也特别气派，还有两三个穿粉色衣服的迎宾小姐姐，很美丽！服务也很不错，还给我们免费升级了房间，早餐品类也很丰富，体验感还是很好的', '["https://dimg04.c-ctrip.com/images/0235112000aqsx85s8C2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000aqt50d4CD9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000aqsvgg0AF95_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '花园大床房', '大床房', '商务出差', 95, 0, 7, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68028542e3c98b09417661f8', '服务态度很好', '["https://dimg04.c-ctrip.com/images/0235212000bvmkz7d0696_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000bvmsh0tEBE6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-10', '红棉大床套房', '套房', '家庭亲子', 6, 0, 11, 3, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68028542e3c98b09417661f9', '花园酒店是此行最满意的酒店。后花园很大很美，花园博物馆非常值得参观。桃园馆可以看到酒店正门。荔湾亭早餐很丰富。周围环境好，有利苑酒家广州酒家点都德都在附近，离地铁非常近。下次再去还住这里。', '["https://dimg04.c-ctrip.com/images/0232912000aqijgohF5D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000aqigp4n1421_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000aqvuzzz51D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000aqiiwd001BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000aqikayqAAB0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000aqvuosy076F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000aqwb7lpEDC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000aqw78p1E979_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-07', '花园双床房', '双床房', '家庭亲子', 94, 0, 82, 8, '["周边配套","交通便利性","整体满意度"]'::jsonb, '周边配套', '交通便利性', '整体满意度'),
('68028542e3c98b09417661fa', '位于市中心的这家老牌酒店交通很不错，地铁口一点点远就到了，房间干净整洁，遇到的服务员都会主动招呼，彬彬有礼。前台的Betty很nice，根据我的会员等级升级了房间，还详细介绍了各项礼遇，谢谢她，总之很愉快的一次入住体验。', '["https://dimg04.c-ctrip.com/images/0234712000cr5vhys6421_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000cr61x8lB742_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000cr64l7mEA64_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-18', '花园大床房', '大床房', '独自旅行', 110, 0, 33, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68028542e3c98b09417661fb', '服务非常好', '["https://dimg04.c-ctrip.com/images/0232l12000bu3sr82D92D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000bu3ptqx2609_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000bu3q5i8566C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000bu3t6mvF09B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000bu3p52u2341_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z12000bu3qxsxDBD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-05', '花园双床房', '双床房', '家庭亲子', 5, 0, 2, 2, '["前台服务","客房服务","退房/入住效率"]'::jsonb, '前台服务', '客房服务', '退房/入住效率'),
('68028542e3c98b09417661fc', '有故事，有深厚文化的酒店', '["https://dimg04.c-ctrip.com/images/0236912000bo9cc0i6E6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000bo9cv59E241_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-07-16', '红棉大床套房', '套房', '朋友出游', 12, 0, 3, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028542e3c98b09417661fe', '墙上 地板上 橱柜上 到处能看到污渍
厕所 防水条都脱落了
浴缸和梳洗台下水超级慢
整个房间就是80年代的感觉
酒店大厅都很气派
就是房间对不起五颗星 最多三颗
服务就不说了 搞错预定房间 都是客人太多的锅
住了三天 一天都没打扫房间
整体服务都很一般 房间很差 和五星酒店不匹配', '["https://dimg04.c-ctrip.com/images/0236v12000anrm7i31427_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000anrm7i578FC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2, 2, '2023-02-13', '城央绿意双床房', '双床房', '朋友出游', 140, 4, 7, 9, '["房间设施","卫生状况","客房服务"]'::jsonb, '房间设施', '卫生状况', '客房服务'),
('68028542e3c98b0941766200', '第一次入住花园酒店，给我的感觉就是愉快??入住酒店那天正好是母亲节，前台为我送上了康乃馨??无论环境，设施，服务，卫生都好。大堂的设计、瀑布餐厅给我们惊艳到了。从酒店门口接待到打扫卫生的服务人员都主动问好。前台的小伙（不好意思没仔细看工牌??）耐心周到的为我们做出合理的安排（我订了大床房和双床房）；餐厅的服务会主动引导安排座位；特别是行政酒廊的Katherine主动引导安排座位，耐心周到的提供服务，主动关心我们的需求，仪态优雅大方。给我们全家留下了深刻的印象。下次有机会我还会入住花园酒店??', '["https://dimg04.c-ctrip.com/images/0235h12000b93rnhm37BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000b93nhg3724A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000b93jkj9946D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000b93nbmkF4BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000b93ttlrE302_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000b93mgovB47E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000b93rz2o417D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000b93r1br1844_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000b93hwv181AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-19', '花园大床房', '大床房', '其他', 248, 0, 4, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68028542e3c98b0941766201', '岭南文化，喜欢一个人在文化气息浓厚的环境内转转，品尝了早餐，相对中国人饮食习惯比较适应，推荐入住，体验客房布草的亲肤感。', '["https://dimg04.c-ctrip.com/images/0234412000ap4mtsz735C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000ap4bkgv50F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000ap4inzz5B7B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000ap4hxc6BD9A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000ap4cw1q9C89_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000ap4i5kjC37D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000ap4h9s3CB07_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000ap4cq642FEC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000ap4dzht7BDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-21', '粤韵大床套房', '套房', '商务出差', 60, 0, 16, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68028542e3c98b0941766202', '酒店位置非常好，地铁就在酒店门口，服务也很到位，卫生很干净。不足之处就是酒店房间设施不好，喷淋要站在浴缸里，没有数据线插孔，这个就很无语，酒店瀑布餐厅环境优美，赞一个。还有推荐酒店正门左拐的建设马路上有一家荔银肠粉老店，那里的肠粉非常好吃??，我连续去吃了三天，推荐虾仁韭黄、和招牌三宝肠粉，艇仔粥也很好吃', '["https://dimg04.c-ctrip.com/images/0231t12000anbcn594C0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000anbujzpCE9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000anb484f7BD7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000anbxsde72CE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000anbsz5lEB23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000anb9v5c706F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-02-11', '花园双床房', '双床房', '家庭亲子', 153, 0, 6, 8, '["房间设施","交通便利性","卫生状况"]'::jsonb, '房间设施', '交通便利性', '卫生状况'),
('68028542e3c98b0941766203', '老牌酒店，大堂很气派，喜欢前台服务员的粉色长裙制服，很特别。晚上到店升级到了套间，房间重新装修的很有设计感，60多平米超大很舒适。楼下超大面积的花园在全国酒店里都是很奢侈的，打理的也很精致，很喜欢花园酒店，历史悠久但没有被时代淘汰，还是那么经典，下次来广州还会入住。', '["https://dimg04.c-ctrip.com/images/0233x12000ajcyuaj2256_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000ajcyo6xBD55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000ajcyxip3939_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000ajcz9lc4F58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000ajcy54u0B5F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000ajd0g3vD8F5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-29', '城央绿意双床房', '双床房', '家庭亲子', 133, 0, 36, 9, '["整体满意度","房间设施","公共设施"]'::jsonb, '整体满意度', '房间设施', '公共设施'),
('68028542e3c98b0941766204', '酒店很大气，进门就是礼宾部，服务很热情。我们初四中午12点抵达的，排队3分钟，但是办理入住的时候真的耗时太久了，至少15分钟！背了大包站着好累。其余都挺好的！入住很开心！花园很美丽，给女儿带了包鱼食，她喂得很开心，下次来广州还会入住。', '["https://dimg04.c-ctrip.com/images/0235s12000ajiiv473E6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000ajigm6k8DC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000ajijpx7A7B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000ajigw0aC357_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000ajiisxo805D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000ajig2i63459_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000ajijd0u23BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-01-30', '花园大床房', '大床房', '家庭亲子', 117, 0, 27, 7, '["前台服务","退房/入住效率","整体满意度"]'::jsonb, '前台服务', '退房/入住效率', '整体满意度'),
('68028542e3c98b0941766205', '在广州出差一直入住花园酒店，这次前台的Tony小哥还给升级了房型，特别感谢。老牌酒店卫生服务都没的说，关键地理位置一流，吃喝出行都是非常方便。体验很棒????', '["https://dimg04.c-ctrip.com/images/0233b12000brczo6a578C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000brczxa93051_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000brczpaw56B1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-27', '花园大床房', '大床房', '商务出差', 79, 0, 20, 8, '["前台服务","整体满意度","交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性'),
('68028542e3c98b0941766206', '这家已经开了30多年的老牌酒店不愧是白金五星级的酒店酒店整体面积规模很大但是老旧这个词跟花园酒店完全没有关系开了这么多年的酒店还保持着这么精致典雅高端不愧是新中国的门面说句实话比现在很多的国际五星酒店要高档的多
是我们中国人自己的酒店疫情三年也没有影响反倒是好多国际联号酒店关闭摘牌虽然这次只入住了一天而且听说次也很不错还有四家米其林餐厅下次来一定要感受一下听说每个餐厅都有特色下次来广州一定还要入住花园酒店', '["https://dimg04.c-ctrip.com/images/0236112000ahoskno74EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000ahoup3cF27E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000ahoue4x887C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-23', '花园大床房', '大床房', '代人预订', 204, 0, 43, 8, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68028542e3c98b0941766207', '五星级的服务！五星级的早餐！房间三星级快捷酒店的设计布置是硬伤！酒店外一侧建设六马路据了解封闭已经长达一年之久，对酒店也是有很大的影响！', '["https://dimg04.c-ctrip.com/images/0236912000aqvyj5eC213_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000aqvylv7969C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000aqvyfdeE052_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000aqvylvu703A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000aqvyl1z7ABC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000aqvyhnn2B2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000aqvyl2jAD66_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000aqvyho5413B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000aqvyjiiB3BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-03-07', '花园双床房', '双床房', '商务出差', 68, 0, 21, 7, '["整体满意度","餐饮设施","房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施'),
('68028542e3c98b0941766208', '最坑爹的一次体验，房间比较小这个就不说了，最主要是冲着携程推荐美食酒店第一名的名头去的，结果去里面的所谓的米其林入选餐厅那个桃园馆吃饭，四个人没有喝酒点了四菜一汤花费了2878元，菜品贵到离谱，例如一份牛肉粒就12粒价格599还有另外15%服务费，下面铺的全部是石头，每人就吃了三粒塞牙缝都不够，所有菜品还另收15%服务费，味道也就一般般，以后再也不可能去了，最坑爹的餐饮没有之一', '["https://dimg04.c-ctrip.com/images/0232v12000aj0akpz4251_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1.7, 1, '2023-01-28', '城央绿意大床房', '大床房', '家庭亲子', 190, 0, 3, 9, '["餐饮设施","价格合理性","整体满意度"]'::jsonb, '餐饮设施', '价格合理性', '整体满意度'),
('68028542e3c98b0941766209', '双人自助晚餐-瀑布餐厅:里面菜品还是不错
小羊公仔一个:非常的帅气逼人
服务：小姐姐态度温柔可亲
环境：不愧中国最早的白金五星级酒店，贝聿铭大师设计的后花园现在都非常惊艳，4家米其林餐厅都是加分项，而是房价非常亲民，喜欢美食酒店的不二选择。', '["https://dimg04.c-ctrip.com/images/0231c12000ahgu3t111AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000ahgvysr38E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-22', '花园双床房', '双床房', '家庭亲子', 120, 0, 34, 8, '["餐饮设施","整体满意度","价格合理性"]'::jsonb, '餐饮设施', '整体满意度', '价格合理性'),
('68028542e3c98b094176620a', '前台大堂的员工都给人一种宾至如归的感觉，特别是前台带人办理入住的粉色衣服的几个小姐姐们超有礼貌的。
服务一流的花园酒店，基本上想要什么都可以商量着来。
设施都是新的，酒店装修复古，但住下却有家的感觉，很喜欢。
福兔迎春盲盒（随机赠送）:酥?年糕 
也可以自己开销，买个花园酒店小羊。', '["https://dimg04.c-ctrip.com/images/0230h12000agu8fhs2ADF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000agu5ggk660B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000agu6v6h68A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000agu7q6z38B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000agu4jzbDD14_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000agu7mhsAB7E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-19', '花园大床房', '大床房', '情侣出游', 141, 0, 4, 8, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68028542e3c98b094176620b', '久闻花园酒店大名，由贝聿铭大师设计，***主席奠基，***爷爷题名。这次入住一晚，果然名不虚传。近40年历史沉淀，体系了厚重的岭南文化，酒店内植被茂盛，瀑布飞泄，锦鲤成群。大堂里美女成群，彬彬有礼。餐厅服务也是一流的，我们坐在“船屋”里品尝粤菜，别有一番风味。', '["https://dimg04.c-ctrip.com/images/0205h12000aerltlu0DAA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0202112000aerheoxFE31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0200812000aergz8t4C9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0202k12000aerjb32BB00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-09', '城央绿意大床房', '大床房', '情侣出游', 130, 0, 98, 9, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68028542e3c98b094176620c', '酒店交通比较方便，旁边有地铁站口，酒店对面就是广州友谊商场，酒店大厅装饰很有特色，还有瀑布餐厅，服务人员比较热情，客房有点小旧', '["https://dimg04.c-ctrip.com/images/0236p12000aq7j89f750D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000b70enlf2584_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000aq7ghuw2A0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000b70imfmA84D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000b70ffrs3DF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-05-10', '城央绿意大床房', '大床房', '其他', 63, 0, 22, 7, '["交通便利性","周边配套","前台服务"]'::jsonb, '交通便利性', '周边配套', '前台服务'),
('68028542e3c98b094176620d', '一次非常愉快的入住体验！首先，是登记入住环节，前台的帅哥Joe非常有耐心有礼貌，看到我带着老人和小孩就给了房间升级。酒店地点非常便利，周边出行无论是打车，坐地铁或者走路出去吃饭按摩都很方便。这几天广州非常炎热，懒得出门，所以在酒店吃了几顿饭。两家粤菜馆各有千秋，其中米其林那家的出品真是意外的精品。自助餐厅的菜式虽然款式不多，但味道很不错。让我想起了香港的半岛酒店自助餐，也是菜式特别少，但样样是精品。美中不足是房间内部味道有一点点陈旧，建议增加香薰。公共区域的味道就很好闻。总之，以后去广州还住花园酒店。', '["https://dimg04.c-ctrip.com/images/0231g12000blabj257D22_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000bla1yudB625_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-06', '花园双床房', '双床房', '家庭亲子', 253, 1, 15, 9, '["前台服务","交通便利性","餐饮设施"]'::jsonb, '前台服务', '交通便利性', '餐饮设施'),
('68028542e3c98b094176620e', '续住第二晚。
小花园简直就是消食胜地，我们还发现了一条金色的鲤鱼。
酒店各种小细节都做得很人性化，浴室还有老人扶手。
离开时还送了小饼干和冰箱贴。', '["https://dimg04.c-ctrip.com/images/0236212000alo51nh6FD5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000alnumjy60BA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000alnrcsi9280_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-05', '花园双床房', '双床房', '家庭亲子', 73, 0, 5, 7, '["公共设施","房间设施","整体满意度"]'::jsonb, '公共设施', '房间设施', '整体满意度'),
('68028542e3c98b094176620f', '出差很方便', '["https://dimg04.c-ctrip.com/images/023352224vfs8tly81996_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023652215fcf2rhxs9A0B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h2234bj5exneoFD3D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-15', '花园双床房', '双床房', '商务出差', 5, 0, 24, 3, '["交通便利性"]'::jsonb, '交通便利性', NULL, NULL),
('68028542e3c98b0941766210', '前台Ariel给升级了红棉房。可以算是套房，很大很好，浴缸也很大小孩子可以在里面游泳了，户外泳池非常棒，让我们从北方来的小孩子抓住了夏天的尾巴还能游泳吃冰淇淋，赞服务，贴心到位，退房时间不用多说就延迟到两点，给力（尤其是国庆旺季期间），四楼博物馆也很棒，住店客人随便进，酒店行政酒廊环境很不错，吃的也丰富，还有livemusic表演。大堂很漂亮，也有表演，门口打车很方便，体验妥妥五星', '["https://dimg04.c-ctrip.com/images/0231v12000cb9iaxa49FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000cb995vl427D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000cb977w12B52_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '花园大床房', '大床房', '家庭亲子', 192, 0, 8, 9, '["前台服务","公共设施","整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度'),
('68028542e3c98b0941766211', '酒店环境很好，自带瀑布，小桥流水。荔湾亭餐厅保留传统特色，口味俱佳。酒店自带的博物馆也值得去参观了解一下，整体服务也是非常棒的。', '["https://dimg04.c-ctrip.com/images/0232612000anbkoz6DB56_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000anbqt4n7E94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000anc6fmw8A3A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-11', '花园大床房', '大床房', '家庭亲子', 64, 0, 8, 8, '["整体满意度","公共设施","餐饮设施"]'::jsonb, '整体满意度', '公共设施', '餐饮设施'),
('68028542e3c98b0941766213', '坐落市区中心，周边很热闹，楼下就是地铁站，交通便利。酒店餐厅很漂亮，大床很软，服务也很好。总之很满意。', '["https://dimg04.c-ctrip.com/images/0233e12000aq7o34qFD2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000aq7hcqa860A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000aq7ixes91A6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-01', '城央绿意大床房', '大床房', '朋友出游', 51, 0, 3, 7, '["交通便利性","整体满意度","房间设施"]'::jsonb, '交通便利性', '整体满意度', '房间设施'),
('68028542e3c98b0941766214', '前台办理要等二三十分钟。也不给升级，店大欺客。这个房间的体验感很一般，太小了。很闷，隔音效果差！', '["https://dimg04.c-ctrip.com/images/0235212000apbc6598F48_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-02-22', '城央绿意大床房', '大床房', '商务出差', 48, 0, 10, 6, '["前台服务","房间设施","安静程度"]'::jsonb, '前台服务', '房间设施', '安静程度'),
('68028542e3c98b0941766215', '酒店设施齐全，部分房间有点旧，但给升级了，前台服务人员一般，但穿粉色衣服的小姐姐太NICE 了，', '["https://dimg04.c-ctrip.com/images/0233h12000aprtvwb236F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000aprsgup1139_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000aprxhyeFA52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000aprum5tD41D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-26', '红棉大床套房', '套房', '商务出差', 48, 0, 10, 6, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68028542e3c98b0941766216', '广州花园酒店的硬件没得说，服务也超级棒！到处都是花，布置的也非常有新年氛围，酒店还给送了一份可爱的点心太赞了！超级贴心！', '["https://dimg04.c-ctrip.com/images/0231712000ajawqw904EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000ajar2fg7A31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000ajau9a0966F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-29', '花园大床房', '大床房', '家庭亲子', 60, 0, 10, 8, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68028542e3c98b0941766217', '很棒的一次入住体验
设施：一应俱全

环境：春节期间入住，整个布置的氛围感的非常好，有春节特色。还有舞龙舞狮表演。

服务：很贴心', '["https://dimg04.c-ctrip.com/images/0234x12000ahlrrpk22C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000ai15z30831C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000ai1424m8C37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000ai14j3nDA92_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000ai17z443690_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-24', '花园双床房', '双床房', '情侣出游', 65, 0, 16, 6, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('68028542e3c98b0941766218', '花园酒店设施齐全，环境不错，去哪个商场都很方便，服务也挺好！', '["https://dimg04.c-ctrip.com/images/0234x12000ap7ocy7AA97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000ap7xu1v77A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000ap7rlxwCAE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000ap7ny2y6DFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000ap7tps07253_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000ap7s3yp6D9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000ap7niag701B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000ap7saldA5B8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000ap7vj6lB5D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-02-22', '红棉大床套房', '套房', '朋友出游', 30, 0, 21, 6, '["周边配套","整体满意度","公共设施"]'::jsonb, '周边配套', '整体满意度', '公共设施'),
('68028542e3c98b0941766219', '老牌花园酒店，入住一如既往的喜欢。广州酒店入住，首选还是花园，主要是装修风格服务特别好，附近逛街美食也很方便', '["https://dimg04.c-ctrip.com/images/0235312000arzo8co19C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000arzeab1A253_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000arzdvk00181_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-16', '城央绿意大床房', '大床房', '独自旅行', 54, 0, 54, 7, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('68028542e3c98b094176621a', '每个接触的服务员都非常nice， 中午来早了，前台办理入住时，得到小妹妹各种温馨介绍，还免费升级粤韵房型，一房一厅，房和厅一样大那种，两个大电视，一键升降窗帘，住的很舒服。客房服务员罗伟星服务热情，对提出的要求都能一一满足，打扫很仔细，处处为客人考虑，值得表扬。博物馆也看了，26个打卡点也人工导览了，带看很仔细，酒店的来龙去脉也清楚了，很棒。早餐看起来不是很多，但吃起来啥都有。周边地铁施工，但窗都是中空玻璃，隔音效果还是比较好的，下次会再入住的。', '["https://dimg04.c-ctrip.com/images/0231912000c4au16b18EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000c4ayfqq49F4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-13', '花园大床房', '大床房', '朋友出游', 225, 0, 3, 9, '["前台服务","客房服务","安静程度"]'::jsonb, '前台服务', '客房服务', '安静程度'),
('68028542e3c98b094176621b', '酒店是老牌五星级酒店，位置在老城区，酒店气派，完全符合五星标准，环境优美，有后花园，酒店性价比超高，不错', '["https://dimg04.c-ctrip.com/images/0230212000ajlz22u6292_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000ajm1b3j7AAC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000ajlzxiuF1C7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-31', '花园双床房', '双床房', '家庭亲子', 52, 0, 8, 6, '["整体满意度","性价比","周边配套"]'::jsonb, '整体满意度', '性价比', '周边配套'),
('68028542e3c98b094176621c', '一进酒店大堂，就被震惊到了，整整一面墙由两公斤金铂打造的水乡风貌和大观园简直太漂亮了！酒店名字由邓小平题词，里面还有一个博物馆，文化和历史气息很浓郁，毫不犹豫又续住了一晚，前台的何经理非常重视客人的建议，总之性价比非常高！我认为是来广州的首选酒店！下次来广州还会住这家！', '["https://dimg04.c-ctrip.com/images/0234p12000aw4xeilFD58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000aw4ytzrA66E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000aw4waj178CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233312000aw4to7eC242_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000aw4wls60BC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000aw4ounj9F85_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-09', '城央绿意大床房', '大床房', '情侣出游', 135, 0, 67, 9, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('68028542e3c98b094176621d', '酒店位置很好，交通便利，出门就是地铁。迎宾小姐姐很热情，只要看到就跑过来问有什么需求，下次还会再来', '["https://dimg04.c-ctrip.com/images/0232r12000ak3ew9iCF99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000ak3a1gl8EFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000ak35ghkAEEB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000ak3d5xv1DCE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-01', '花园大床房', '大床房', '情侣出游', 49, 0, 3, 7, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68028542e3c98b094176621f', '很棒的酒店,就是早餐没有了原来推着小车吃早茶点心的氛围了有点遗憾', '["https://dimg04.c-ctrip.com/images/0237412000aq2uglx8E98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000aq2uotwD5EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000aq2uo3k355B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000aq2uob71ECC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-28', '红棉双床套房', '套房', '朋友出游', 32, 0, 20, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68028542e3c98b0941766221', '下次还会去选择，特别感谢入住前台大眼帅哥房间升级，态度也超级nice。酒店里有好几家米其林，附近也有几家老字号，推介吃货首选酒店。嫌弃房间设施老旧的客人，可以选择付费升级相对新的房间。', '["https://dimg04.c-ctrip.com/images/0231c12000at85sn0075C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000at85wh5AE02_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-26', '红棉大床套房', '套房', '家庭亲子', 92, 0, 17, 7, '["前台服务","周边配套","房间设施"]'::jsonb, '前台服务', '周边配套', '房间设施'),
('68028542e3c98b0941766222', '服务非常到位，环境也不错，各方面都很方便，总体感觉98分', '["https://dimg04.c-ctrip.com/images/0234f12000c0beg7u3496_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000c0bb6rtB221_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000c0besxm2A97_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-26', '红棉大床套房', '套房', '家庭亲子', 28, 0, 3, 4, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('68028543e3c98b0941766223', '12月内两次入住花园大酒店，前台员工专业、热情，第一次入住时就免费升级到高级房，还赠送给我们花园行政酒廊体验，入住期间可以去花园品下午茶、看瀑布、观赏池中的游弋的锦鲤；房间布局设计是我喜欢的风格，干净整洁，床品柔软舒适； 酒店位置优越，酒店外就是地铁站；街对面就是友谊广场，广州酒家、陶陶居、點都德、利苑酒家等都在附近；出行、购物、美食都很方便。 最赞的是：酒店前台、行政酒廊、桃园餐厅、大厅等服务人员都很热情??谢谢，入住期间很愉快！会推荐给亲朋好友，下次来广州花园酒店仍然是我的第一选择！', '["https://dimg04.c-ctrip.com/images/0234r2234awpimjio926C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-19', '花园大床房', '大床房', '家庭亲子', 246, 0, 552, 9, '["前台服务","整体满意度","交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性'),
('68028543e3c98b0941766224', '酒店交通岀入方便，酒店用餐环境不错', '["https://dimg04.c-ctrip.com/images/0236p12000aq7j89f750D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231b12000aq7ghuw2A0B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-01', '城央绿意大床房', '大床房', '商务出差', 17, 0, 22, 4, '["交通便利性","餐饮设施"]'::jsonb, '交通便利性', '餐饮设施', NULL),
('68028543e3c98b0941766226', '入住体验挺好的，前台服务生托尼，服务态度非常好，待旅客热情周到，赞一个！', '["https://dimg04.c-ctrip.com/images/0232212000bhncisyD338_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-24', '花园大床房', '大床房', '其他', 36, 0, 13, 6, '["前台服务"]'::jsonb, '前台服务', NULL, NULL),
('68028543e3c98b0941766227', '酒店过年氛围浓烈，服务态度好，环境好，出酒店就有地铁，出行方便', '["https://dimg04.c-ctrip.com/images/0231u12000arvylzk7E58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000arw47dt3A84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000arvydnt8F05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000arw36u8BD4B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-15', '城央绿意大床房', '大床房', '家庭亲子', 31, 0, 87, 6, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68028543e3c98b094176622a', '环境不错，早餐丰富', '["https://dimg04.c-ctrip.com/images/0232y12000bbjqj1q4F12_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000bbjpisx5F7C_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0237212000bbjz8oh2CBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-30', '城央绿意大床房', '大床房', '商务出差', 9, 0, 41, 4, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68028543e3c98b094176622c', '房间构造差一点，但氛围感拉满', '["https://dimg04.c-ctrip.com/images/0233k12000ar7o36qF43D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-09', '花园大床房', '大床房', '商务出差', 14, 0, 7, 5, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68028543e3c98b094176622d', '各方面都很好 非常满意', '["https://dimg04.c-ctrip.com/images/0234312000ar1jiyxF373_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000ar1fxeg7867_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-08', '红棉双床套房', '套房', '家庭亲子', 11, 0, 28, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028543e3c98b094176622f', '每次出差都会选择入住广州花园酒店，房间非常干净，舒适，整洁。前台Justin帮助我快速办理入住，退房收到lavinia的问候，询问我入住感受，非常满意的一次体验，下次还会选择花园～满分好评', '["https://dimg04.c-ctrip.com/images/0231d12000f3iaj7kB04A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000f3i5ogkA6E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000f3i15w5A8C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231q12000f3iai4vE52D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-12', '花园大床房', '大床房', '其他', 94, 0, 125, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68028543e3c98b0941766231', '入住广州花园酒店最大的感受就是这里的服务真的非常贴心，不论是环境还是地理位置，都非常棒，行政酒廊的服务也非常值得表扬，特别是carrie热情的问候和微笑，除此之外还有zoey，Nikki，Chloe,Kulvir 的服务都非常到位，整体体验非常棒。', '["https://dimg04.c-ctrip.com/images/0232c2224v4g39ug0053F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-17', '花园大床房', '大床房', '商务出差', 124, 0, 12, 8, '["前台服务","整体满意度","周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套')
